import React, { useEffect } from "react";
import { useNavigate } from "react-router-dom";

function FreelancerDashboard() {
  const navigate = useNavigate();

  useEffect(() => {
    const token = localStorage.getItem("access");
    if (!token) {
      navigate("/");
    }
  }, [navigate]);

  const handleLogout = () => {
    localStorage.clear();
    navigate("/");
  };

  return (
    <div className="container">
      <h2>Freelancer Dashboard</h2>
      <p>Welcome, Freelancer!</p>
      <div className="dashboard-actions">
        <button onClick={() => navigate("/projects")} style={{ marginRight: "10px" }}>Find Projects</button>
        <button onClick={() => navigate("/proposals")} style={{ marginRight: "10px" }}>My Proposals</button>
        <button onClick={() => navigate("/profile")} style={{ marginRight: "10px" }}>My Profile</button>
        <button onClick={handleLogout}>Logout</button>
      </div>
    </div>
  );
}

export default FreelancerDashboard;
